class Solution {
    public int[] memLeak(int memory1, int memory2) {
        int[] result = new int[3];
        int temp1 = memory1, temp2 = memory2;

        for (int i = 1; i <= temp1 && i <= temp2; i++) {
            if (temp1 > temp2) {
                temp1 -= i;
            } else {
                temp2 -= i;
            }
            result[0] = i;
        }
        result[1] = temp1;
        result[2] = temp2;

        return result;
    }
}
```

